"use client";

import { useEffect, useState } from "react";
import { format } from "date-fns";
import { id } from "date-fns/locale";
import {
  ArrowUpCircle,
  ArrowDownCircle,
  Search,
  Filter,
  RefreshCw,
  Calendar,
  ChevronDown,
  Trash2,
} from "lucide-react";
import { getBrowserSupabaseClient } from "@/lib/supabase";
import type { Database } from "@/types/database.types";

type TransactionRow = Database["public"]["Tables"]["transactions"]["Row"];

type FilterState = {
  search: string;
  type: "all" | "pemasukan" | "pengeluaran";
  category: string;
  urgency: "all" | "rendah" | "sedang" | "tinggi";
  dateRange: "all" | "7days" | "30days" | "90days";
};

const urgencyColors = {
  rendah:
    "bg-emerald-50 text-emerald-700 dark:bg-emerald-950/40 dark:text-emerald-400",
  sedang: "bg-amber-50 text-amber-700 dark:bg-amber-950/40 dark:text-amber-400",
  tinggi: "bg-red-50 text-red-700 dark:bg-red-950/40 dark:text-red-400",
};

const typeColors = {
  pemasukan:
    "bg-emerald-50 text-emerald-700 dark:bg-emerald-950/40 dark:text-emerald-400",
  pengeluaran:
    "bg-rose-50 text-rose-700 dark:bg-rose-950/40 dark:text-rose-400",
};

const kelompokLabels: Record<string, string> = {
  aset_lancar: "Aset Lancar",
  kewajiban_jangka_pendek: "Kewajiban Jangka Pendek",
  pendapatan: "Pendapatan",
  beban_operasional: "Beban Operasional",
};

export function TransactionHistory() {
  const supabase = getBrowserSupabaseClient();
  const [transactions, setTransactions] = useState<TransactionRow[]>([]);
  const [filteredTransactions, setFilteredTransactions] = useState<
    TransactionRow[]
  >([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showFilters, setShowFilters] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const [filters, setFilters] = useState<FilterState>({
    search: "",
    type: "all",
    category: "all",
    urgency: "all",
    dateRange: "all",
  });

  // Get unique categories from transactions
  const categories = Array.from(
    new Set(transactions.map((t) => t.kategori)),
  ).sort();

  useEffect(() => {
    if (!supabase) {
      setError("Supabase tidak terkonfigurasi");
      setIsLoading(false);
      return;
    }

    void loadTransactions();
  }, [supabase]);

  useEffect(() => {
    applyFilters();
  }, [filters, transactions]);

  const loadTransactions = async () => {
    if (!supabase) return;

    setIsLoading(true);
    setError(null);

    const { data, error } = await supabase
      .from("transactions")
      .select("*")
      .order("created_at", { ascending: false });

    if (error) {
      setError(error.message);
    } else {
      setTransactions((data as TransactionRow[]) ?? []);
    }

    setIsLoading(false);
  };

  const applyFilters = () => {
    let result = [...transactions];

    // Search filter
    if (filters.search) {
      const searchLower = filters.search.toLowerCase();
      result = result.filter(
        (t) =>
          t.deskripsi.toLowerCase().includes(searchLower) ||
          t.kategori.toLowerCase().includes(searchLower) ||
          t.nominal.toString().includes(searchLower),
      );
    }

    // Type filter
    if (filters.type !== "all") {
      result = result.filter((t) => t.tipe_transaksi === filters.type);
    }

    // Category filter
    if (filters.category !== "all") {
      result = result.filter((t) => t.kategori === filters.category);
    }

    // Urgency filter
    if (filters.urgency !== "all") {
      result = result.filter((t) => t.tingkat_urgensi === filters.urgency);
    }

    // Date range filter
    if (filters.dateRange !== "all") {
      const now = new Date();
      const daysMap = { "7days": 7, "30days": 30, "90days": 90 };
      const days = daysMap[filters.dateRange as keyof typeof daysMap];
      const cutoff = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
      result = result.filter((t) => new Date(t.created_at) >= cutoff);
    }

    setFilteredTransactions(result);
  };

  const handleDelete = async (id: string) => {
    if (!supabase) return;
    if (!confirm("Apakah Anda yakin ingin menghapus transaksi ini?")) return;

    setDeletingId(id);

    const { error } = await supabase.from("transactions").delete().eq("id", id);

    if (error) {
      alert(`Gagal menghapus: ${error.message}`);
    } else {
      setTransactions((prev) => prev.filter((t) => t.id !== id));
    }

    setDeletingId(null);
  };

  const clearFilters = () => {
    setFilters({
      search: "",
      type: "all",
      category: "all",
      urgency: "all",
      dateRange: "all",
    });
  };

  const hasActiveFilters =
    filters.search ||
    filters.type !== "all" ||
    filters.category !== "all" ||
    filters.urgency !== "all" ||
    filters.dateRange !== "all";

  return (
    <section className="rounded-3xl border border-slate-200/50 bg-white dark:border-slate-800/50 dark:bg-slate-900 p-6 shadow-sm transition-colors duration-300">
      {/* Header */}
      <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
        <div>
          <span className="text-xs font-bold uppercase tracking-[0.2em] text-indigo-600 dark:text-indigo-400">
            Riwayat Transaksi
          </span>
          <h2 className="mt-2 text-xl sm:text-2xl font-bold text-slate-900 dark:text-white">
            Semua Transaksi
          </h2>
          <p className="mt-2 text-xs sm:text-sm leading-relaxed text-slate-500 dark:text-slate-400">
            Lacak dan lihat semua transaksi keuangan usaha Anda.
          </p>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`inline-flex h-10 items-center gap-2 rounded-xl border px-4 text-sm font-semibold transition cursor-pointer ${
              showFilters || hasActiveFilters
                ? "border-indigo-200 bg-indigo-50 text-indigo-700 dark:border-indigo-800 dark:bg-indigo-950/40 dark:text-indigo-300"
                : "border-slate-200 bg-white text-slate-700 hover:bg-slate-50 dark:border-slate-800 dark:bg-slate-900 dark:text-slate-350 dark:hover:bg-slate-800"
            }`}
          >
            <Filter className="h-4 w-4" />
            Filter
            {hasActiveFilters && (
              <span className="flex h-5 w-5 items-center justify-center rounded-full bg-indigo-600 text-white text-xs">
                !
              </span>
            )}
          </button>
          <button
            onClick={() => void loadTransactions()}
            className="inline-flex h-10 w-10 items-center justify-center rounded-xl border border-slate-200 bg-white text-slate-600 hover:bg-slate-50 dark:border-slate-800 dark:bg-slate-900 dark:text-slate-400 dark:hover:bg-slate-800 transition cursor-pointer"
            aria-label="Refresh data"
          >
            <RefreshCw
              className={`h-4 w-4 ${isLoading ? "animate-spin" : ""}`}
            />
          </button>
        </div>
      </div>

      {/* Filters Panel */}
      {showFilters && (
        <div className="mb-6 rounded-2xl border border-slate-200/50 bg-slate-50/50 dark:border-slate-800/50 dark:bg-slate-950/40 p-5">
          <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-5">
            {/* Search */}
            <div className="relative lg:col-span-2">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
              <input
                type="text"
                placeholder="Cari transaksi..."
                value={filters.search}
                onChange={(e) =>
                  setFilters((f) => ({ ...f, search: e.target.value }))
                }
                className="h-10 w-full rounded-xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 pl-10 pr-4 text-sm text-slate-900 dark:text-white placeholder-slate-400 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/10"
              />
            </div>

            {/* Type */}
            <select
              value={filters.type}
              onChange={(e) =>
                setFilters((f) => ({
                  ...f,
                  type: e.target.value as FilterState["type"],
                }))
              }
              className="h-10 rounded-xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 px-3 text-sm text-slate-900 dark:text-white outline-none transition focus:border-indigo-500 cursor-pointer"
            >
              <option value="all">Semua Tipe</option>
              <option value="pemasukan">Pemasukan</option>
              <option value="pengeluaran">Pengeluaran</option>
            </select>

            {/* Category */}
            <select
              value={filters.category}
              onChange={(e) =>
                setFilters((f) => ({ ...f, category: e.target.value }))
              }
              className="h-10 rounded-xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 px-3 text-sm text-slate-900 dark:text-white outline-none transition focus:border-indigo-500 cursor-pointer"
            >
              <option value="all">Semua Kategori</option>
              {categories.map((cat) => (
                <option key={cat} value={cat}>
                  {cat}
                </option>
              ))}
            </select>

            {/* Date Range */}
            <select
              value={filters.dateRange}
              onChange={(e) =>
                setFilters((f) => ({
                  ...f,
                  dateRange: e.target.value as FilterState["dateRange"],
                }))
              }
              className="h-10 rounded-xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 px-3 text-sm text-slate-900 dark:text-white outline-none transition focus:border-indigo-500 cursor-pointer"
            >
              <option value="all">Semua Waktu</option>
              <option value="7days">7 Hari Terakhir</option>
              <option value="30days">30 Hari Terakhir</option>
              <option value="90days">90 Hari Terakhir</option>
            </select>
          </div>

          {hasActiveFilters && (
            <div className="mt-4 flex items-center justify-between">
              <p className="text-xs text-slate-500 dark:text-slate-400">
                Menampilkan {filteredTransactions.length} dari{" "}
                {transactions.length} transaksi
              </p>
              <button
                onClick={clearFilters}
                className="text-xs font-semibold text-indigo-600 hover:text-indigo-500 dark:text-indigo-400"
              >
                Reset Filter
              </button>
            </div>
          )}
        </div>
      )}

      {/* Loading State */}
      {isLoading && (
        <div className="flex items-center justify-center rounded-2xl border border-dashed border-slate-200 dark:border-slate-800/80 bg-slate-50/40 dark:bg-slate-900/20 p-10">
          <RefreshCw className="h-6 w-6 animate-spin text-indigo-500" />
          <span className="ml-3 text-sm text-slate-500 dark:text-slate-400">
            Memuat transaksi...
          </span>
        </div>
      )}

      {/* Error State */}
      {error && !isLoading && (
        <div className="rounded-2xl border border-red-200/50 bg-red-50/40 dark:border-red-950/50 dark:bg-red-950/10 p-4 text-sm text-red-900 dark:text-red-400">
          {error}
        </div>
      )}

      {/* Empty State */}
      {!isLoading && !error && filteredTransactions.length === 0 && (
        <div className="rounded-2xl border border-dashed border-slate-200 dark:border-slate-800/80 bg-slate-50/40 dark:bg-slate-900/20 p-10 text-center">
          <Calendar className="mx-auto h-10 w-10 text-slate-400 dark:text-slate-600" />
          <p className="mt-3 text-sm font-semibold text-slate-600 dark:text-slate-400">
            {hasActiveFilters
              ? "Tidak ada transaksi yang cocok dengan filter"
              : "Belum ada transaksi"}
          </p>
          <p className="mt-1 text-xs text-slate-500 dark:text-slate-500">
            {hasActiveFilters
              ? "Coba ubah atau hapus filter Anda"
              : "Catat transaksi pertama Anda menggunakan Voice Ledger"}
          </p>
        </div>
      )}

      {/* Transaction List */}
      {!isLoading && !error && filteredTransactions.length > 0 && (
        <div className="space-y-3">
          {filteredTransactions.map((transaction) => (
            <div
              key={transaction.id}
              className="group relative rounded-2xl border border-slate-200/50 bg-white p-4 transition-colors duration-300 hover:border-slate-300 dark:border-slate-800/50 dark:bg-slate-900/50 dark:hover:border-slate-700"
            >
              <div className="flex items-start gap-4">
                {/* Type Icon */}
                <div
                  className={`flex h-10 w-10 shrink-0 items-center justify-center rounded-xl ${
                    transaction.tipe_transaksi === "pemasukan"
                      ? "bg-emerald-50 text-emerald-600 dark:bg-emerald-950/40 dark:text-emerald-400"
                      : "bg-rose-50 text-rose-600 dark:bg-rose-950/40 dark:text-rose-400"
                  }`}
                >
                  {transaction.tipe_transaksi === "pemasukan" ? (
                    <ArrowUpCircle className="h-5 w-5" />
                  ) : (
                    <ArrowDownCircle className="h-5 w-5" />
                  )}
                </div>

                {/* Main Content */}
                <div className="min-w-0 flex-1">
                  <div className="flex flex-wrap items-center gap-2">
                    <span
                      className={`inline-flex items-center gap-1 rounded-full px-2.5 py-0.5 text-xs font-bold uppercase ${
                        typeColors[transaction.tipe_transaksi]
                      }`}
                    >
                      {transaction.tipe_transaksi}
                    </span>
                    <span
                      className={`inline-flex items-center gap-1 rounded-full px-2.5 py-0.5 text-xs font-bold uppercase ${
                        urgencyColors[transaction.tingkat_urgensi]
                      }`}
                    >
                      {transaction.tingkat_urgensi}
                    </span>
                    <span className="text-xs text-slate-400 dark:text-slate-500">
                      {kelompokLabels[transaction.kelompok_keuangan]}
                    </span>
                  </div>

                  <p className="mt-2 text-sm font-semibold text-slate-900 dark:text-white">
                    {transaction.deskripsi || "Tanpa deskripsi"}
                  </p>

                  <div className="mt-2 flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-slate-500 dark:text-slate-400">
                    <span className="font-medium text-indigo-600 dark:text-indigo-400">
                      {transaction.kategori}
                    </span>
                    <span>
                      {format(
                        new Date(transaction.created_at),
                        "dd MMM yyyy, HH:mm",
                        {
                          locale: id,
                        },
                      )}
                    </span>
                  </div>
                </div>

                {/* Amount & Actions */}
                <div className="flex flex-col items-end gap-2">
                  <span
                    className={`text-base font-bold ${
                      transaction.tipe_transaksi === "pemasukan"
                        ? "text-emerald-600 dark:text-emerald-400"
                        : "text-rose-600 dark:text-rose-400"
                    }`}
                  >
                    {transaction.tipe_transaksi === "pemasukan" ? "+" : "-"}
                    Rp{transaction.nominal.toLocaleString("id-ID")}
                  </span>

                  <button
                    onClick={() => void handleDelete(transaction.id)}
                    disabled={deletingId === transaction.id}
                    className="flex h-8 w-8 items-center justify-center rounded-lg border border-transparent text-slate-400 opacity-0 transition hover:border-red-200 hover:bg-red-50 hover:text-red-600 group-hover:opacity-100 dark:hover:border-red-900 dark:hover:bg-red-950/20 dark:hover:text-red-400 disabled:opacity-50"
                    aria-label="Delete transaction"
                  >
                    {deletingId === transaction.id ? (
                      <RefreshCw className="h-4 w-4 animate-spin" />
                    ) : (
                      <Trash2 className="h-4 w-4" />
                    )}
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Summary Footer */}
      {!isLoading && !error && filteredTransactions.length > 0 && (
        <div className="mt-6 rounded-2xl border border-slate-200/50 bg-slate-50/50 dark:border-slate-800/50 dark:bg-slate-950/40 p-4">
          <div className="flex flex-wrap items-center justify-between gap-4 text-sm">
            <span className="text-slate-500 dark:text-slate-400">
              Total {filteredTransactions.length} transaksi
            </span>
            <div className="flex gap-6">
              <div>
                <span className="text-slate-500 dark:text-slate-400">
                  Total Pemasukan:{" "}
                </span>
                <span className="font-semibold text-emerald-600 dark:text-emerald-400">
                  Rp
                  {filteredTransactions
                    .filter((t) => t.tipe_transaksi === "pemasukan")
                    .reduce((sum, t) => sum + t.nominal, 0)
                    .toLocaleString("id-ID")}
                </span>
              </div>
              <div>
                <span className="text-slate-500 dark:text-slate-400">
                  Total Pengeluaran:{" "}
                </span>
                <span className="font-semibold text-rose-600 dark:text-rose-400">
                  Rp
                  {filteredTransactions
                    .filter((t) => t.tipe_transaksi === "pengeluaran")
                    .reduce((sum, t) => sum + t.nominal, 0)
                    .toLocaleString("id-ID")}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
    </section>
  );
}

import { jsPDF } from "jspdf";
import type { Database } from "@/types/database.types";

type TransactionRow = Database["public"]["Tables"]["transactions"]["Row"];

type FinancialSummary = {
  totalIncome: number;
  totalExpense: number;
  netBalance: number;
  transactionCount: number;
};

const formatCurrency = (amount: number): string => {
  return "Rp" + amount.toLocaleString("id-ID");
};

const formatDate = (dateString: string): string => {
  const date = new Date(dateString);
  return date.toLocaleDateString("id-ID", {
    day: "2-digit",
    month: "long",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
};

const kelompokLabels: Record<string, string> = {
  aset_lancar: "Aset Lancar",
  kewajiban_jangka_pendek: "Kewajiban Jangka Pendek",
  pendapatan: "Pendapatan",
  beban_operasional: "Beban Operasional",
};

const urgencyLabels: Record<string, string> = {
  rendah: "Rendah",
  sedang: "Sedang",
  tinggi: "Tinggi",
};

export const exportTransactionsToPDF = (
  transactions: TransactionRow[],
  summary: FinancialSummary
): void => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  const margin = 20;
  let yPos = margin;

  // Colors (matching design system)
  const primaryColor: [number, number, number] = [79, 70, 229]; // Indigo 600
  const textColor: [number, number, number] = [15, 23, 42]; // Slate 900
  const mutedColor: [number, number, number] = [100, 116, 139]; // Slate 500
  const successColor: [number, number, number] = [16, 185, 129]; // Emerald 500
  const dangerColor: [number, number, number] = [244, 63, 94]; // Rose 500

  // Header
  doc.setFillColor(...primaryColor);
  doc.rect(0, 0, pageWidth, 40, "F");

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(20);
  doc.setFont("helvetica", "bold");
  doc.text("LarisManis AI", margin, 25);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text("Laporan Transaksi Keuangan UMKM", margin, 33);

  doc.setTextColor(255, 255, 255);
  doc.text(
    `Dicetak: ${new Date().toLocaleDateString("id-ID", {
      day: "2-digit",
      month: "long",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    })}`,
    pageWidth - margin,
    33,
    { align: "right" }
  );

  yPos = 55;

  // Summary Section
  doc.setTextColor(...textColor);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text("Ringkasan Keuangan", margin, yPos);
  yPos += 10;

  // Summary Cards
  const cardWidth = (pageWidth - margin * 2 - 20) / 3;
  const cardHeight = 25;

  // Total Income Card
  doc.setFillColor(236, 253, 245); // Emerald 50
  doc.roundedRect(margin, yPos, cardWidth, cardHeight, 3, 3, "F");
  doc.setTextColor(...successColor);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("TOTAL PEMASUKAN", margin + 5, yPos + 8);
  doc.setFontSize(12);
  doc.text(formatCurrency(summary.totalIncome), margin + 5, yPos + 18);

  // Total Expense Card
  doc.setFillColor(255, 240, 241); // Rose 50
  doc.roundedRect(margin + cardWidth + 10, yPos, cardWidth, cardHeight, 3, 3, "F");
  doc.setTextColor(...dangerColor);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("TOTAL PENGELUARAN", margin + cardWidth + 15, yPos + 8);
  doc.setFontSize(12);
  doc.text(formatCurrency(summary.totalExpense), margin + cardWidth + 15, yPos + 18);

  // Net Balance Card
  const balanceColor = summary.netBalance >= 0 ? successColor : dangerColor;
  doc.setFillColor(summary.netBalance >= 0 ? 236 : 255, summary.netBalance >= 0 ? 253 : 240, summary.netBalance >= 0 ? 245 : 241);
  doc.roundedRect(margin + (cardWidth + 10) * 2, yPos, cardWidth, cardHeight, 3, 3, "F");
  doc.setTextColor(...balanceColor);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("SALDO BERSIH", margin + (cardWidth + 10) * 2 + 5, yPos + 8);
  doc.setFontSize(12);
  doc.text(
    (summary.netBalance >= 0 ? "+" : "-") + formatCurrency(Math.abs(summary.netBalance)),
    margin + (cardWidth + 10) * 2 + 5,
    yPos + 18
  );

  yPos += cardHeight + 15;

  // Transaction List Header
  doc.setTextColor(...textColor);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(`Daftar Transaksi (${transactions.length} transaksi)`, margin, yPos);
  yPos += 10;

  // Table Header
  doc.setFillColor(248, 250, 252); // Slate 50
  doc.rect(margin, yPos, pageWidth - margin * 2, 10, "F");
  doc.setTextColor(...mutedColor);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("TANGGAL", margin + 3, yPos + 7);
  doc.text("TIPE", margin + 45, yPos + 7);
  doc.text("KATEGORI", margin + 75, yPos + 7);
  doc.text("DESKRIPSI", margin + 115, yPos + 7);
  doc.text("NOMINAL", pageWidth - margin - 3, yPos + 7, { align: "right" });

  yPos += 12;

  // Table Rows
  doc.setFont("helvetica", "normal");
  transactions.forEach((transaction, index) => {
    // Check if we need a new page
    if (yPos > 270) {
      doc.addPage();
      yPos = margin;

      // Repeat header on new page
      doc.setFillColor(248, 250, 252);
      doc.rect(margin, yPos, pageWidth - margin * 2, 10, "F");
      doc.setTextColor(...mutedColor);
      doc.setFontSize(8);
      doc.setFont("helvetica", "bold");
      doc.text("TANGGAL", margin + 3, yPos + 7);
      doc.text("TIPE", margin + 45, yPos + 7);
      doc.text("KATEGORI", margin + 75, yPos + 7);
      doc.text("DESKRIPSI", margin + 115, yPos + 7);
      doc.text("NOMINAL", pageWidth - margin - 3, yPos + 7, { align: "right" });
      yPos += 12;
    }

    // Alternate row background
    if (index % 2 === 0) {
      doc.setFillColor(250, 250, 250);
      doc.rect(margin, yPos - 3, pageWidth - margin * 2, 10, "F");
    }

    // Date
    doc.setTextColor(...mutedColor);
    doc.setFontSize(7);
    doc.text(
      new Date(transaction.created_at).toLocaleDateString("id-ID", {
        day: "2-digit",
        month: "short",
        year: "numeric",
      }),
      margin + 3,
      yPos + 4
    );

    // Type Badge
    const typeColor = transaction.tipe_transaksi === "pemasukan" ? successColor : dangerColor;
    doc.setTextColor(...typeColor);
    doc.setFontSize(7);
    doc.setFont("helvetica", "bold");
    doc.text(
      transaction.tipe_transaksi === "pemasukan" ? "MSK" : "KLR",
      margin + 45,
      yPos + 4
    );

    // Category
    doc.setTextColor(...textColor);
    doc.setFont("helvetica", "normal");
    doc.setFontSize(7);
    doc.text(transaction.kategori, margin + 75, yPos + 4);

    // Description
    doc.setTextColor(...mutedColor);
    doc.setFontSize(7);
    const description = transaction.deskripsi.length > 30
      ? transaction.deskripsi.substring(0, 30) + "..."
      : transaction.deskripsi || "-";
    doc.text(description, margin + 115, yPos + 4);

    // Amount
    doc.setTextColor(...typeColor);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(8);
    doc.text(
      (transaction.tipe_transaksi === "pemasukan" ? "+" : "-") + formatCurrency(transaction.nominal),
      pageWidth - margin - 3,
      yPos + 4,
      { align: "right" }
    );

    yPos += 10;
  });

  // Footer
  const footerY = doc.internal.pageSize.getHeight() - 15;
  doc.setTextColor(...mutedColor);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text(
    "LarisManis AI - Asisten Keuangan Suara & Pemasaran Visual UMKM",
    margin,
    footerY
  );
  doc.text(
    `Halaman 1 dari ${doc.getNumberOfPages()}`,
    pageWidth - margin,
    footerY,
    { align: "right" }
  );

  // Save the PDF
  doc.save(`LarisManisAI_Transaksi_${new Date().toISOString().split("T")[0]}.pdf`);
};

export const exportBudgetReportToPDF = (
  budgets: Array<{
    kategori: string;
    tipe_transaksi: "pemasukan" | "pengeluaran";
    target_nominal: number;
    periode_bulan: string;
    actual: number;
  }>
): void => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  const margin = 20;
  let yPos = margin;

  // Colors
  const primaryColor: [number, number, number] = [79, 70, 229];
  const textColor: [number, number, number] = [15, 23, 42];
  const mutedColor: [number, number, number] = [100, 116, 139];
  const successColor: [number, number, number] = [16, 185, 129];
  const dangerColor: [number, number, number] = [244, 63, 94];
  const warningColor: [number, number, number] = [245, 158, 11];

  // Header
  doc.setFillColor(...primaryColor);
  doc.rect(0, 0, pageWidth, 40, "F");

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(20);
  doc.setFont("helvetica", "bold");
  doc.text("LarisManis AI", margin, 25);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text("Laporan Budget & Target Bulanan", margin, 33);

  doc.setTextColor(255, 255, 255);
  doc.text(
    `Dicetak: ${new Date().toLocaleDateString("id-ID", {
      day: "2-digit",
      month: "long",
      year: "numeric",
    })}`,
    pageWidth - margin,
    33,
    { align: "right" }
  );

  yPos = 55;

  // Budget List
  doc.setTextColor(...textColor);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(`Daftar Budget (${budgets.length} budget)`, margin, yPos);
  yPos += 10;

  // Table Header
  doc.setFillColor(248, 250, 252);
  doc.rect(margin, yPos, pageWidth - margin * 2, 10, "F");
  doc.setTextColor(...mutedColor);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("KATEGORI", margin + 5, yPos + 7);
  doc.text("TIPE", margin + 55, yPos + 7);
  doc.text("PERIODE", margin + 85, yPos + 7);
  doc.text("TARGET", margin + 125, yPos + 7);
  doc.text("REALISASI", margin + 155, yPos + 7);
  doc.text("STATUS", pageWidth - margin - 5, yPos + 7, { align: "right" });

  yPos += 12;

  doc.setFont("helvetica", "normal");

  budgets.forEach((budget, index) => {
    if (yPos > 270) {
      doc.addPage();
      yPos = margin;
    }

    if (index % 2 === 0) {
      doc.setFillColor(250, 250, 250);
      doc.rect(margin, yPos - 3, pageWidth - margin * 2, 10, "F");
    }

    // Category
    doc.setTextColor(...textColor);
    doc.setFontSize(8);
    doc.text(budget.kategori, margin + 5, yPos + 4);

    // Type
    const typeColor = budget.tipe_transaksi === "pemasukan" ? successColor : dangerColor;
    doc.setTextColor(...typeColor);
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.text(
      budget.tipe_transaksi === "pemasukan" ? "Pemasukan" : "Pengeluaran",
      margin + 55,
      yPos + 4
    );

    // Period
    doc.setTextColor(...mutedColor);
    doc.setFont("helvetica", "normal");
    doc.setFontSize(8);
    const [year, month] = budget.periode_bulan.split("-");
    const periodDate = new Date(parseInt(year), parseInt(month) - 1);
    doc.text(
      periodDate.toLocaleDateString("id-ID", { month: "long", year: "numeric" }),
      margin + 85,
      yPos + 4
    );

    // Target
    doc.setTextColor(...textColor);
    doc.setFontSize(8);
    doc.text(formatCurrency(budget.target_nominal), margin + 125, yPos + 4);

    // Actual
    doc.setTextColor(...textColor);
    doc.setFontSize(8);
    doc.text(formatCurrency(budget.actual), margin + 155, yPos + 4);

    // Status
    const percentage = (budget.actual / budget.target_nominal) * 100;
    const isOverBudget = budget.actual > budget.target_nominal;

    if (isOverBudget) {
      doc.setTextColor(...dangerColor);
      doc.setFont("helvetica", "bold");
      doc.text("Over Budget", pageWidth - margin - 5, yPos + 4, { align: "right" });
    } else if (percentage >= 80) {
      doc.setTextColor(...warningColor);
      doc.setFont("helvetica", "bold");
      doc.text(`${percentage.toFixed(0)}%`, pageWidth - margin - 5, yPos + 4, { align: "right" });
    } else {
      doc.setTextColor(...successColor);
      doc.setFont("helvetica", "bold");
      doc.text("On Track", pageWidth - margin - 5, yPos + 4, { align: "right" });
    }

    yPos += 10;
  });

  // Footer
  const footerY = doc.internal.pageSize.getHeight() - 15;
  doc.setTextColor(...mutedColor);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text(
    "LarisManis AI - Asisten Keuangan Suara & Pemasaran Visual UMKM",
    margin,
    footerY
  );
  doc.text(
    `Halaman 1 dari ${doc.getNumberOfPages()}`,
    pageWidth - margin,
    footerY,
    { align: "right" }
  );

  doc.save(`LarisManisAI_Budget_${new Date().toISOString().split("T")[0]}.pdf`);
};
